// Class-component error boundary. Hooks can't catch render-time errors,
// so we use componentDidCatch. Re-renders cleanly when `key` changes,
// which is how we reset on navigation. For small surfaces (drawer,
// palette) pass a compact `fallback` to avoid blanketing the page.

import { Component } from "react";
import { AlertTriangle, RotateCw, Home } from "lucide-react";
import { Link } from "react-router-dom";

const IS_DEV = process.env.NODE_ENV !== "production";

export default class ErrorBoundary extends Component {
  constructor(props) {
    super(props);
    this.state = { error: null };
    this.reset = this.reset.bind(this);
  }

  static getDerivedStateFromError(error) {
    return { error };
  }

  componentDidCatch(error, errorInfo) {
    if (IS_DEV) {
      console.error("[ErrorBoundary]", error, errorInfo);
    }
    this.props.onError?.(error, errorInfo);
  }

  componentDidUpdate(prevProps) {
    if (this.state.error && prevProps.resetKey !== this.props.resetKey) {
      this.reset();
    }
  }

  reset() {
    this.setState({ error: null });
    this.props.onReset?.();
  }

  render() {
    const { error } = this.state;
    if (error) {
      const { fallback } = this.props;
      if (typeof fallback === "function") return fallback({ error, reset: this.reset });
      if (fallback) return fallback;
      return <PageFallback error={error} onReset={this.reset} />;
    }
    return this.props.children;
  }
}

function PageFallback({ error, onReset }) {
  return (
    <div
      data-testid="error-boundary-fallback"
      className="min-h-screen bg-bg-base text-white font-body grid place-items-center px-6 py-12"
    >
      <div className="max-w-md text-center">
        <div className="inline-flex items-center justify-center w-14 h-14 rounded-full bg-amber-500/10 border border-amber-500/30 mb-6">
          <AlertTriangle className="w-7 h-7 text-amber-400" />
        </div>
        <div className="font-mono text-[10px] uppercase tracking-[0.25em] text-amber-300 mb-3">
          Unhandled error
        </div>
        <h1 className="font-heading text-3xl sm:text-4xl font-black tracking-tight leading-[1.05] mb-3">
          Something broke.
        </h1>
        <p className="text-zinc-400 text-sm leading-relaxed mb-6">
          An unexpected error crashed this view. The rest of the app should still work — try again or head back to the homepage.
        </p>
        {IS_DEV && error?.message && (
          <pre className="text-left bg-white/[0.03] border border-white/10 rounded-lg p-3 text-[11px] text-zinc-500 font-mono overflow-auto max-h-32 mb-6 whitespace-pre-wrap break-words">
            {error.message}
          </pre>
        )}
        <div className="flex items-center justify-center gap-3 flex-wrap">
          <button
            data-testid="error-boundary-retry"
            onClick={onReset}
            className="inline-flex items-center gap-2 bg-emerald-500 hover:bg-emerald-400 text-black font-bold uppercase tracking-[0.18em] text-xs px-4 py-2.5 rounded-sm transition-colors"
          >
            <RotateCw className="w-3.5 h-3.5" /> Try again
          </button>
          <Link
            to="/"
            onClick={onReset}
            className="inline-flex items-center gap-2 border border-white/15 hover:border-white/30 text-white font-bold uppercase tracking-[0.18em] text-xs px-4 py-2.5 rounded-sm transition-colors"
          >
            <Home className="w-3.5 h-3.5" /> Home
          </Link>
        </div>
      </div>
    </div>
  );
}

// Compact fallback for overlays that should never blanket the page.
export function InlineFallback({ message = "Couldn't load this view.", onReset }) {
  return (
    <div className="p-6 text-center flex flex-col items-center gap-3 bg-bg-base border border-amber-500/20 rounded-2xl m-4">
      <AlertTriangle className="w-5 h-5 text-amber-400" />
      <p className="text-zinc-300 text-sm">{message}</p>
      {onReset && (
        <button
          onClick={onReset}
          className="inline-flex items-center gap-1.5 border border-white/15 hover:border-emerald-500/40 hover:text-emerald-400 text-white font-bold uppercase tracking-[0.18em] text-[10px] px-3 py-1.5 rounded-sm transition-colors"
        >
          <RotateCw className="w-3 h-3" /> Try again
        </button>
      )}
    </div>
  );
}
