// Shared Sparkline used by the DetailDrawer chart. Cardinal-spline path with
// gradient fill, dashed median reference line, per-point dots, and a Y/X axis.
//
// Sizing model:
//   - Default: renders at width=100% of its parent (the parent card controls
//     the actual size) and uses a 520x170 viewBox for the coordinate space.
//     With width=100% + viewBox + preserveAspectRatio="none", the SVG
//     stretches uniformly to fill the parent — that turned out to look
//     awful (chart line and text both stretched). The current behaviour is:
//     SVG fills the parent width and height stays in proportion (height is
//     auto, set by aspect-ratio 520/170) — this matches the previous
//     responsive design but without the stretching artifact.
//   - compact: hides Y-axis labels and reduces left padding to 0 so the
//     line can start at the very left of a narrow card. Used on mobile
//     where the Y-axis labels would either crowd the data or get cut.
//   - Fixed size callers can pass explicit width/height for 1:1 rendering.

import { useState, useRef, useEffect, useMemo } from "react";
import { createPortal } from "react-dom";
import { fmt } from "@/lib/parseItem";

const VW = 520;
const VH = 170;

function PortalTooltip({ svgRef, point, w, h, children }) {
  const [style, setStyle] = useState({ visibility: "hidden" });
  const ref = useRef(null);

  useEffect(() => {
    if (!svgRef.current || !ref.current) return;
    const svg = svgRef.current.getBoundingClientRect();
    const scaleX = svg.width / w;
    const scaleY = svg.height / h;
    let x = svg.left + point[0] * scaleX;
    let y = svg.top + point[1] * scaleY;
    const tooltipW = ref.current.offsetWidth;
    const tooltipH = ref.current.offsetHeight;
    const pad = 12;
    x = Math.max(pad + tooltipW / 2, Math.min(window.innerWidth - pad - tooltipW / 2, x));
    const above = point[1] < h / 2;
    const finalY = above ? y + 10 : y - 10 - tooltipH;
    setStyle({
      left: `${x}px`,
      top: `${finalY}px`,
      transform: "translateX(-50%)",
    });
  }, [svgRef, point, w, h]);

  return (
    <div
      ref={ref}
      className="fixed pointer-events-none z-[300]"
      style={{ ...style, visibility: style.left ? "visible" : "hidden" }}
    >
      {children}
    </div>
  );
}

const TIMEFRAME_MS = { all: 0, "1D": 86400000, "7D": 604800000, "30D": 2592000000 };

function smoothPath(points, tension = 0.2) {
  if (points.length === 0) return "";
  if (points.length === 1) return `M${points[0][0].toFixed(1)},${points[0][1].toFixed(1)}`;
  if (points.length === 2) return `M${points[0][0].toFixed(1)},${points[0][1].toFixed(1)} L${points[1][0].toFixed(1)},${points[1][1].toFixed(1)}`;
  let d = `M${points[0][0].toFixed(1)},${points[0][1].toFixed(1)}`;
  for (let i = 0; i < points.length - 1; i++) {
    const p0 = points[i - 1] || points[i];
    const p1 = points[i];
    const p2 = points[i + 1];
    const p3 = points[i + 2] || p2;
    const cp1x = p1[0] + (p2[0] - p0[0]) * tension;
    const cp1y = p1[1] + (p2[1] - p1[1]) * tension;
    const cp2x = p2[0] - (p3[0] - p1[0]) * tension;
    const cp2y = p2[1] - (p3[1] - p1[1]) * tension;
    d += ` C${cp1x.toFixed(1)},${cp1y.toFixed(1)} ${cp2x.toFixed(1)},${cp2y.toFixed(1)} ${p2[0].toFixed(1)},${p2[1].toFixed(1)}`;
  }
  return d;
}

function filterByTimeframe(series, timeframe) {
  const cutoff = TIMEFRAME_MS[timeframe] || 0;
  if (cutoff === 0) return series;
  const now = Date.now();
  return series.filter(p => now - (p.t || p.ts) <= cutoff);
}

export function Sparkline({
  series,
  median = 0,
  width,
  height,
  showAxis = true,
  compact = false,
  gradientId = "sparkline-fill",
  showDots = true,
  pointTooltip = null,
  onPointClick = null,
  timeframe = "all",
  onTimeframeChange = null,
}) {
  const svgRef = useRef(null);
  const [internalTimeframe, setInternalTimeframe] = useState(timeframe);
  const activeTimeframe = onTimeframeChange ? timeframe : internalTimeframe;
  const handleTimeframeChange = onTimeframeChange || setInternalTimeframe;
  const [hover, setHover] = useState(null);
  const filteredSeries = filterByTimeframe(series, activeTimeframe);

  // If the caller passes an explicit width/height, honour it. Otherwise fill
  // the parent and let the viewBox scale.
  const fixedSize = width != null && height != null;
  const w = fixedSize ? width : VW;
  const h = fixedSize ? height : VH;

  // In compact mode, kill the Y-axis labels and the left padding they
  // need, so the chart line starts at the very left of the card. The
  // X-axis is still drawn but the date labels are shrunk.
  const showY = showAxis && !compact;
  const padL = showY ? 56 : 8;
  const padR = 8;
  const padT = 12;
  const padB = showAxis ? 30 : 8;
  const innerW = w - padL - padR;
  const innerH = h - padT - padB;
  // Safety margin to prevent line clipping at chart bounds (stroke width = 2px)
  const safetyMargin = 4;

  const vals = filteredSeries?.map((p) => p.v) || [];
  let minV = vals.length > 0 ? Math.min(...vals) : 0;
  let maxV = vals.length > 0 ? Math.max(...vals) : 0;
  if (median > 0) {
    minV = Math.min(minV, median);
    maxV = Math.max(maxV, median);
  }
  const range = maxV - minV || 1;
  const head = range * 0.12;
  minV -= head;
  maxV += head;
  const adjRange = maxV - minV;

  const stepX = filteredSeries?.length > 1 ? innerW / (filteredSeries.length - 1) : 0;
  const points = useMemo(() => {
    if (!filteredSeries || filteredSeries.length < 2) return [];
    return filteredSeries.map((p, i) => {
      const x = padL + i * stepX;
      // Apply safety margin to prevent line clipping at chart bounds
      const t = (p.v - minV) / adjRange;
      const y = padT + safetyMargin + (innerH - 2 * safetyMargin) * (1 - t);
      return [x, y];
    });
  }, [filteredSeries, padL, stepX, minV, adjRange, padT, safetyMargin, innerH]);

  if (!filteredSeries || filteredSeries.length < 2) {
    return (
      <div
        className="font-mono text-[11px] uppercase tracking-wider text-zinc-600 grid place-items-center w-full h-full min-h-[120px]"
        style={fixedSize ? { width, height } : undefined}
      >
        {filteredSeries && filteredSeries.length === 1 ? "Not enough data for history" : "Not enough data"}
      </div>
    );
  }

  const line = smoothPath(points);
  const last = points[points.length - 1];
  const first = points[0];
  // Clip area to inner bounds, not including safety margin
  const area = `${line} L${last[0].toFixed(1)},${(padT + innerH).toFixed(1)} L${first[0].toFixed(1)},${(padT + innerH).toFixed(1)} Z`;

  const medianY = padT + safetyMargin + (innerH - 2 * safetyMargin) * (1 - (median - minV) / adjRange);
  const showMedian = median > 0 && median >= minV && median <= maxV;

  const yTicks = showY ? [minV, minV + adjRange / 2, maxV] : [];
  const xTicks = showAxis
    ? filteredSeries.length > 4
      ? [filteredSeries[0], filteredSeries[Math.floor(filteredSeries.length / 2)], filteredSeries[filteredSeries.length - 1]]
      : [filteredSeries[0], filteredSeries[filteredSeries.length - 1]]
    : [];

  return (
    <div
      className="relative w-full h-full"
      style={fixedSize ? { width, height } : undefined}
    >
      <svg
        ref={svgRef}
        width="100%"
        height="100%"
        viewBox={`0 0 ${w} ${h}`}
        preserveAspectRatio="xMidYMid meet"
        className="block"
        style={fixedSize ? { width, height } : undefined}
      >
        <defs>
          <linearGradient id={gradientId} x1="0" y1="0" x2="0" y2="1">
            <stop offset="0%" stopColor="#10B981" stopOpacity={0.45} />
            <stop offset="100%" stopColor="#10B981" stopOpacity={0} />
          </linearGradient>
          <clipPath id={`${gradientId}-clip`}>
            <rect x={padL} y={padT + safetyMargin} width={innerW} height={innerH - 2 * safetyMargin} />
          </clipPath>
        </defs>

        {showY && yTicks.map((v, i) => {
          const t = (v - minV) / adjRange;
          const y = padT + safetyMargin + (innerH - 2 * safetyMargin) * (1 - t);
          return (
            <g key={`y-${i}`}>
              <line x1={padL} y1={y} x2={padL + innerW} y2={y} stroke="rgba(255,255,255,0.05)" strokeWidth={1} />
              <text x={padL - 8} y={y + 3} fill="#52525b" fontSize={9} textAnchor="end" fontFamily="ui-monospace, monospace">
                {fmt(v)}
              </text>
            </g>
          );
        })}

        <g clipPath={`url(#${gradientId}-clip)`}>
          <path d={area} fill={`url(#${gradientId})`} />
          <path d={line} fill="none" stroke="#10B981" strokeWidth={2} strokeLinejoin="round" strokeLinecap="round" />
          {showDots && points.map(([x, y], i) => {
            const isLast = i === points.length - 1;
            const isHover = hover === i;
            return (
              <g key={`p-${i}`}>
                {isHover && (
                  <line x1={x} y1={padT} x2={x} y2={padT + innerH} stroke="#FBBF24" strokeWidth={0.5} strokeDasharray="2 3" opacity={0.6} />
                )}
                <circle
                  cx={x} cy={y} r={10}
                  fill="transparent"
                  className={onPointClick || pointTooltip ? "cursor-pointer" : ""}
                  onMouseEnter={() => setHover(i)}
                  onMouseLeave={() => setHover((h) => (h === i ? null : h))}
                  onClick={() => onPointClick && onPointClick(series[i], i)}
                />
                {isLast ? (
                  <>
                    <circle cx={x} cy={y} r={isHover ? 6 : 4.5} fill={isHover ? "#FBBF24" : "rgba(16,185,129,0.25)"} className="pointer-events-none transition-all" />
                    <circle cx={x} cy={y} r={isHover ? 4 : 2.5} fill={isHover ? "#FBBF24" : "#34d399"} className="pointer-events-none transition-all" />
                  </>
                ) : (
                  <circle
                    cx={x} cy={y}
                    r={isHover ? 5 : 3.5}
                    fill={isHover ? "#FBBF24" : "#10B981"}
                    stroke={isHover ? "#FBBF24" : "transparent"}
                    strokeWidth={1.5}
                    className="pointer-events-none transition-all"
                  />
                )}
              </g>
            );
          })}
        </g>

        {showMedian && (
          <g clipPath={`url(#${gradientId}-clip)`}>
            <line x1={padL} y1={medianY} x2={padL + innerW} y2={medianY} stroke="#FBBF24" strokeWidth={1.2} strokeDasharray="5 4" />
          </g>
        )}

        {showAxis && xTicks.map((p, i) => {
          const x = padL + (filteredSeries.indexOf(p)) * stepX;
          const label = new Date(p.t || p.ts).toLocaleDateString(undefined, { month: "short", day: "numeric" });
          return (
            <text key={`x-${i}`} x={x} y={h - 10} fill="#52525b" fontSize={compact ? 7 : 9} textAnchor="middle" fontFamily="ui-monospace, monospace">
              {label}
            </text>
          );
        })}

        {showY && showMedian && (
          <text x={padL + innerW - 4} y={medianY - 4} fill="#FBBF24" fontSize={9} textAnchor="end" fontFamily="ui-monospace, monospace">
            median {fmt(median)}
          </text>
        )}
      </svg>

      {hover !== null && pointTooltip && points[hover] && createPortal(
        <PortalTooltip svgRef={svgRef} point={points[hover]} w={w} h={h}>
          {pointTooltip({ point: filteredSeries[hover], index: hover })}
        </PortalTooltip>,
        document.body
      )}

      <div className="flex gap-1 justify-center mt-2">
        {["all", "30D", "7D", "1D"].map((tf) => (
          <button
            key={tf}
            onClick={() => handleTimeframeChange(tf)}
            className={`text-xs px-2 py-0.5 rounded ${
              activeTimeframe === tf
                ? "bg-emerald-500/20 text-emerald-400"
                : "bg-zinc-800 text-zinc-500 hover:bg-zinc-700"
            }`}
          >
            {tf === "all" ? "All" : tf}
          </button>
        ))}
      </div>
    </div>
  );
}
